package dev.modichamiya.eclipse.gameplay.ability;

import dev.modichamiya.eclipse.registry.ContentKey;
import java.time.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public final class AbilityService {public record CastResult(boolean success,String reason,AbilityDefinition ability){}private record Cooldown(UUID player,ContentKey ability){}private final Map<ContentKey,AbilityDefinition>definitions=new ConcurrentHashMap<>();private final Map<UUID,Map<String,Double>>resources=new ConcurrentHashMap<>();private final Map<Cooldown,Instant>cooldowns=new ConcurrentHashMap<>();public void register(AbilityDefinition ability){if(definitions.putIfAbsent(ability.key(),ability)!=null)throw new IllegalArgumentException("Duplicate ability");}public void setResource(UUID player,String type,double amount){if(amount<0)throw new IllegalArgumentException();resources.computeIfAbsent(player,id->new ConcurrentHashMap<>()).put(type,amount);}public synchronized CastResult cast(UUID player,ContentKey key,Instant now){AbilityDefinition ability=Optional.ofNullable(definitions.get(key)).orElseThrow();Cooldown cooldown=new Cooldown(player,key);Instant until=cooldowns.get(cooldown);if(until!=null&&until.isAfter(now))return new CastResult(false,"cooldown",ability);Map<String,Double>pool=resources.computeIfAbsent(player,id->new ConcurrentHashMap<>());double available=pool.getOrDefault(ability.resource(),0d);if(available<ability.cost())return new CastResult(false,"resource",ability);pool.put(ability.resource(),available-ability.cost());cooldowns.put(cooldown,now.plus(ability.cooldown()));return new CastResult(true,"ok",ability);}public Duration remaining(UUID player,ContentKey ability,Instant now){Instant until=cooldowns.get(new Cooldown(player,ability));return until==null||!until.isAfter(now)?Duration.ZERO:Duration.between(now,until);}}
